#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, K;
        scanf("%lld %lld", &N, &K);
        long long per = N / (K + 1); // floor division
        long long received = K * per;
        long long net = N - received;
        printf("%lld\n", net);
    }
    return 0;
}

